/**
 * MedX avatar runtime — runs on `npm run start` via medx-runtime-registry.cjs
 * User and supplier avatars with initials fallback and presence indicators.
 */
const AVATAR_SIZES = Object.freeze({
  xs: { dimension: 24, fontSize: 10 },
  sm: { dimension: 32, fontSize: 12 },
  md: { dimension: 40, fontSize: 14 },
  lg: { dimension: 56, fontSize: 18 },
  xl: { dimension: 72, fontSize: 22 },
});

const PRESENCE_STATES = Object.freeze({
  online: { color: "bg-emerald-500", label: "Online" },
  away: { color: "bg-amber-500", label: "Away" },
  busy: { color: "bg-red-500", label: "Busy" },
  offline: { color: "bg-muted-foreground/40", label: "Offline" },
});

const AVATAR_COLORS = [
  "bg-red-500",
  "bg-orange-500",
  "bg-amber-500",
  "bg-emerald-500",
  "bg-teal-500",
  "bg-blue-500",
  "bg-indigo-500",
  "bg-violet-500",
  "bg-pink-500",
];

const avatarRegistry = new Map();

function hashString(str) {
  let hash = 0;
  for (let i = 0; i < str.length; i++) {
    hash = (hash << 5) - hash + str.charCodeAt(i);
    hash |= 0;
  }
  return Math.abs(hash);
}

function getInitials(name) {
  const parts = String(name ?? "")
    .trim()
    .split(/\s+/)
    .filter(Boolean);
  if (parts.length === 0) return "?";
  if (parts.length === 1) return parts[0].slice(0, 2).toUpperCase();
  return (parts[0][0] + parts[parts.length - 1][0]).toUpperCase();
}

function getAvatarColor(seed) {
  const index = hashString(seed) % AVATAR_COLORS.length;
  return AVATAR_COLORS[index];
}

function createAvatar(config) {
  const id = config.id ?? `medx-avatar-${avatarRegistry.size + 1}`;
  const size = config.size ?? "md";
  const avatar = {
    id,
    name: config.name ?? "Unknown",
    email: config.email ?? null,
    imageUrl: config.imageUrl ?? null,
    initials: config.initials ?? getInitials(config.name),
    size,
    sizeStyles: AVATAR_SIZES[size] ?? AVATAR_SIZES.md,
    fallbackColor: getAvatarColor(config.email ?? config.name ?? id),
    presence: config.presence ?? "offline",
    presenceStyles: PRESENCE_STATES[config.presence ?? "offline"],
    role: config.role ?? null,
    org: config.org ?? null,
  };
  avatarRegistry.set(id, avatar);
  return avatar;
}

function createAvatarGroup(users, options = {}) {
  const max = options.max ?? 4;
  const size = options.size ?? "sm";
  const visible = users.slice(0, max).map((u, i) =>
    createAvatar({ ...u, id: `group-${options.groupId ?? "default"}-${i}`, size }),
  );
  const overflow = Math.max(0, users.length - max);
  return { visible, overflow, total: users.length };
}

function getAvatarSnapshot(id) {
  const avatar = avatarRegistry.get(id);
  if (!avatar) return null;
  return {
    id: avatar.id,
    display: avatar.imageUrl ? "image" : "initials",
    initials: avatar.initials,
    presence: avatar.presence,
    dimension: avatar.sizeStyles.dimension,
  };
}

async function runMedxAvatar() {
  console.log("[medx:ui:avatar] runtime initialized");
  console.log(`[medx:ui:avatar] sizes=${Object.keys(AVATAR_SIZES).length}`);

  const team = [
    { name: "Sarah Chen", email: "s.chen@medx.io", presence: "online", role: "Inventory Manager" },
    { name: "James Okonkwo", email: "j.okonkwo@medx.io", presence: "away", role: "Compliance Lead" },
    { name: "Maria Garcia", email: "m.garcia@medx.io", presence: "busy", role: "Procurement" },
    { name: "Alex Kim", email: "a.kim@medx.io", presence: "online", role: "Cold Chain Ops" },
    { name: "Pat Williams", email: "p.williams@medx.io", presence: "offline", role: "Analyst" },
    { name: "Supplier Bot", email: "api@supplier.com", presence: "online", role: "Integration" },
  ];

  const group = createAvatarGroup(team, { groupId: "ops-team", max: 4, size: "sm" });
  createAvatar({
    name: "MedX System",
    size: "lg",
    presence: "online",
    imageUrl: null,
  });

  console.log(`[medx:ui:avatar] registered=${avatarRegistry.size}`);
  console.log(`[medx:ui:avatar] group visible=${group.visible.length} overflow=+${group.overflow}`);
  console.log("[medx:ui:avatar] bootstrap complete");
}

module.exports = runMedxAvatar;
